import React from 'react';
import './news.css';
import Image from './phonk_wallpaper.jpg';


function NewsPage() {
  return(
  <div id="content">
      <div id="news_card">
        <p>тут типа свежие новости</p>
        <img src={Image} alt="Ну нету авы, я что сделаю!"></img>
      </div>
      <div id="news_card">
        <p>тут типа тоже какие то новости</p>
      </div>
      <div id="news_card">
        <p>тут типа статьи, которые какой то чел написал</p>
      </div>
  </div>
  )
}

export default NewsPage;
